# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messaging, performance dashboards and reporting for a small team
collaboration tool.

The public surface is the :class:`TeamCollaborationManager` class together
with a handful of lightweight value objects (``User``, ``Project``, ``Task``,
``Message``, ``Attachment``, ``Rating``) and a small exception hierarchy.

Design notes
------------
* A single re-entrant lock is shared by the manager and every sub-store so
  that cross-store operations (cascading deletes, reporting, ...) remain
  atomic. The sub-stores expose that same lock object via ``_lock`` which is
  what the concurrency tests assert on.
* Identifiers are globally unique across every entity type. They are handed
  out by a single monotonically increasing counter starting at ``1``.
* Every getter returns an independent *clone* of the stored object so that
  callers can never mutate internal state by accident.
"""

import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Set, Tuple


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a user can hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for a report."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Value objects
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime

    def clone(self) -> "Attachment":
        return Attachment(
            filename=self.filename,
            size=self.size,
            uploaded_by=self.uploaded_by,
            uploaded_at=self.uploaded_at,
        )


@dataclass
class User:
    """A registered user."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime

    def clone(self) -> "User":
        return User(
            id=self.id,
            username=self.username,
            email=self.email,
            role=self.role,
            created_at=self.created_at,
        )


@dataclass
class Project:
    """A project owned by a user."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime

    def clone(self) -> "Project":
        return Project(
            id=self.id,
            name=self.name,
            description=self.description,
            start_date=self.start_date,
            end_date=self.end_date,
            owner_id=self.owner_id,
            created_at=self.created_at,
        )


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime

    def clone(self) -> "Task":
        return Task(
            id=self.id,
            project_id=self.project_id,
            title=self.title,
            status=self.status,
            assignee_id=self.assignee_id,
            deadline=self.deadline,
            started_at=self.started_at,
            completed_at=self.completed_at,
            created_at=self.created_at,
        )


@dataclass
class Message:
    """A message posted to a project or task, optionally threaded."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None

    def clone(self) -> "Message":
        return Message(
            id=self.id,
            author_id=self.author_id,
            body=self.body,
            project_id=self.project_id,
            task_id=self.task_id,
            parent_id=self.parent_id,
            attachments=[a.clone() for a in self.attachments],
            created_at=self.created_at,
            edited_at=self.edited_at,
        )


@dataclass
class Rating:
    """A peer rating left for a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime

    def clone(self) -> "Rating":
        return Rating(
            id=self.id,
            rater_id=self.rater_id,
            ratee_id=self.ratee_id,
            score=self.score,
            feedback=self.feedback,
            task_id=self.task_id,
            created_at=self.created_at,
        )


# ---------------------------------------------------------------------------
# Sub-stores
#
# Each store owns a slice of state but shares the single manager lock. Store
# helpers assume the caller already holds that lock (the manager wraps every
# public operation in ``with self._lock``).
# ---------------------------------------------------------------------------
class _BaseStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._users: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}

    def _get(self, user_id: int) -> User:
        user = self._users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _add(self, user: User) -> None:
        self._users[user.id] = user
        self._by_username[user.username] = user.id
        self._by_email[user.email.lower()] = user.id

    def _remove(self, user_id: int) -> None:
        user = self._users.pop(user_id, None)
        if user is not None:
            self._by_username.pop(user.username, None)
            self._by_email.pop(user.email.lower(), None)

    def _set_username(self, user: User, new_username: str) -> None:
        self._by_username.pop(user.username, None)
        user.username = new_username
        self._by_username[new_username] = user.id

    def _set_email(self, user: User, new_email: str) -> None:
        self._by_email.pop(user.email.lower(), None)
        user.email = new_email
        self._by_email[new_email.lower()] = user.id

    def _all(self) -> List[User]:
        return list(self._users.values())


class ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._projects: Dict[int, Project] = {}

    def _get(self, project_id: int) -> Project:
        project = self._projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _add(self, project: Project) -> None:
        self._projects[project.id] = project

    def _remove(self, project_id: int) -> None:
        self._projects.pop(project_id, None)

    def _all(self) -> List[Project]:
        return list(self._projects.values())


class TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._tasks: Dict[int, Task] = {}
        self._by_project: Dict[int, Set[int]] = {}
        self._by_assignee: Dict[int, Set[int]] = {}

    def _get(self, task_id: int) -> Task:
        task = self._tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _add(self, task: Task) -> None:
        self._tasks[task.id] = task
        self._by_project.setdefault(task.project_id, set()).add(task.id)
        if task.assignee_id is not None:
            self._by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def _remove(self, task_id: int) -> None:
        task = self._tasks.pop(task_id, None)
        if task is None:
            return
        bucket = self._by_project.get(task.project_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                self._by_project.pop(task.project_id, None)
        if task.assignee_id is not None:
            assignee_bucket = self._by_assignee.get(task.assignee_id)
            if assignee_bucket is not None:
                assignee_bucket.discard(task_id)
                if not assignee_bucket:
                    self._by_assignee.pop(task.assignee_id, None)

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        if task.assignee_id is not None:
            bucket = self._by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self._by_assignee.pop(task.assignee_id, None)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self._by_assignee.setdefault(new_assignee, set()).add(task.id)

    def _project_task_ids(self, project_id: int) -> List[int]:
        return sorted(self._by_project.get(project_id, set()))

    def _assignee_task_ids(self, assignee_id: int) -> List[int]:
        return sorted(self._by_assignee.get(assignee_id, set()))


class MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._messages: Dict[int, Message] = {}
        self._by_project: Dict[int, Set[int]] = {}
        self._by_task: Dict[int, Set[int]] = {}

    def _get(self, message_id: int) -> Message:
        message = self._messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    def _add(self, message: Message) -> None:
        self._messages[message.id] = message
        if message.project_id is not None:
            self._by_project.setdefault(message.project_id, set()).add(message.id)
        if message.task_id is not None:
            self._by_task.setdefault(message.task_id, set()).add(message.id)

    def _remove(self, message_id: int) -> None:
        message = self._messages.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self._by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message_id)
                if not bucket:
                    self._by_project.pop(message.project_id, None)
        if message.task_id is not None:
            bucket = self._by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message_id)
                if not bucket:
                    self._by_task.pop(message.task_id, None)

    def _project_message_ids(self, project_id: int) -> List[int]:
        return sorted(self._by_project.get(project_id, set()))

    def _task_message_ids(self, task_id: int) -> List[int]:
        return sorted(self._by_task.get(task_id, set()))


class PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, List[Rating]] = {}

    def _add_rating(self, rating: Rating) -> None:
        self._ratings[rating.id] = rating
        self._by_ratee.setdefault(rating.ratee_id, []).append(rating)

    def _ratings_for(self, ratee_id: int) -> List[Rating]:
        return list(self._by_ratee.get(ratee_id, []))


class ReportStore(_BaseStore):
    """Stateless reporting subsystem; logic lives on the manager."""


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates every collaboration operation behind a shared lock."""

    def __init__(self, now=None) -> None:
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.utcnow
        self._id_seq = 0

        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceStore(self._lock)
        self.reports = ReportStore(self._lock)

    # -- internal helpers --------------------------------------------------
    def _next_id(self) -> int:
        self._id_seq += 1
        return self._id_seq

    @staticmethod
    def _require_non_empty_str(value, field_name: str) -> str:
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(field_name))
        return value.strip()

    @staticmethod
    def _validate_email(email) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        local, _, domain = cleaned.partition("@")
        if not local or not domain or "@" in domain:
            raise ValidationError("invalid email address")
        return cleaned

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            clean_username = self._require_non_empty_str(username, "username")
            clean_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if clean_username in self.users._by_username:
                raise DuplicateError(
                    "username '{0}' already exists".format(clean_username)
                )
            if clean_email.lower() in self.users._by_email:
                raise DuplicateError(
                    "email '{0}' already exists".format(clean_email)
                )
            user = User(
                id=self._next_id(),
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users._add(user)
            return user.clone()

    def get_user(self, user_id) -> User:
        with self._lock:
            return self.users._get(user_id).clone()

    def list_users(self) -> List[User]:
        with self._lock:
            return [u.clone() for u in sorted(self.users._all(), key=lambda x: x.id)]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self.users._get(user_id)

            new_username = None
            if username is not None:
                new_username = self._require_non_empty_str(username, "username")
                existing = self.users._by_username.get(new_username)
                if existing is not None and existing != user_id:
                    raise DuplicateError(
                        "username '{0}' already exists".format(new_username)
                    )

            new_email = None
            if email is not None:
                new_email = self._validate_email(email)
                existing = self.users._by_email.get(new_email.lower())
                if existing is not None and existing != user_id:
                    raise DuplicateError(
                        "email '{0}' already exists".format(new_email)
                    )

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_username is not None:
                self.users._set_username(user, new_username)
            if new_email is not None:
                self.users._set_email(user, new_email)
            if role is not None:
                user.role = role
            return user.clone()

    def delete_user(self, user_id) -> None:
        with self._lock:
            self.users._get(user_id)
            for project in self.projects._all():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns project {1}".format(user_id, project.id)
                    )
            for task_id in self.tasks._assignee_task_ids(user_id):
                task = self.tasks._tasks[task_id]
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user {0} has an open task {1}".format(user_id, task_id)
                    )
            self.users._remove(user_id)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            self.users._get(owner_id)
            clean_name = self._require_non_empty_str(name, "name")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")
            project = Project(
                id=self._next_id(),
                name=clean_name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._add(project)
            return project.clone()

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self.projects._get(project_id).clone()

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                p.clone() for p in sorted(self.projects._all(), key=lambda x: x.id)
            ]

    def update_project(
        self, project_id, name=None, description=None, start_date=None, end_date=None
    ) -> Project:
        with self._lock:
            project = self.projects._get(project_id)

            new_name = project.name
            if name is not None:
                new_name = self._require_non_empty_str(name, "name")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return project.clone()

    def delete_project(self, project_id) -> None:
        with self._lock:
            self.projects._get(project_id)
            for task_id in list(self.tasks._project_task_ids(project_id)):
                self._remove_task(task_id)
            for message_id in list(self.messages._project_message_ids(project_id)):
                self.messages._remove(message_id)
            self.projects._remove(project_id)

    def _remove_task(self, task_id: int) -> None:
        for message_id in list(self.messages._task_message_ids(task_id)):
            self.messages._remove(message_id)
        self.tasks._remove(task_id)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self.projects._get(project_id)
            clean_title = self._require_non_empty_str(title, "title")
            if assignee_id is not None:
                self.users._get(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before project start")
            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks._add(task)
            return task.clone()

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self.tasks._get(task_id).clone()

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self.projects._get(project_id)
            return [
                self.tasks._tasks[t].clone()
                for t in self.tasks._project_task_ids(project_id)
            ]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self.users._get(assignee_id)
            return [
                self.tasks._tasks[t].clone()
                for t in self.tasks._assignee_task_ids(assignee_id)
            ]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self.tasks._get(task_id)
            self.users._get(assignee_id)
            self.tasks._set_assignee(task, assignee_id)
            return task.clone()

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self.tasks._get(task_id)
            self.users._get(new_assignee_id)
            self.tasks._set_assignee(task, new_assignee_id)
            return task.clone()

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self.tasks._get(task_id)
            self.tasks._set_assignee(task, None)
            return task.clone()

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self.tasks._get(task_id)
            if deadline is not None:
                project = self.projects._get(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self.tasks._get(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return task.clone()

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ) -> Message:
        with self._lock:
            self.users._get(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                self.projects._get(project_id)
            if task_id is not None:
                self.tasks._get(task_id)
            if parent_id is not None:
                self.messages._get(parent_id)

            built_attachments = self._build_attachments(attachments, author_id)
            text = body if body is not None else ""
            if not text.strip() and not built_attachments:
                raise ValidationError("message requires a body or an attachment")

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=self._now(),
                edited_at=None,
            )
            self.messages._add(message)
            return message.clone()

    def _build_attachments(self, attachments, uploader_id) -> List[Attachment]:
        built: List[Attachment] = []
        if not attachments:
            return built
        now = self._now()
        for entry in attachments:
            filename, data = entry
            clean_name = self._require_non_empty_str(filename, "filename")
            built.append(
                Attachment(
                    filename=clean_name,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=now,
                )
            )
        return built

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self.messages._get(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            text = new_body if new_body is not None else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message requires a body or an attachment")
            message.body = text
            message.edited_at = self._now()
            return message.clone()

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self.messages._get(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may add attachments")
            clean_name = self._require_non_empty_str(filename, "filename")
            message.attachments.append(
                Attachment(
                    filename=clean_name,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._now(),
                )
            )
            return message.clone()

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self.projects._get(project_id)
            return [
                self.messages._messages[m].clone()
                for m in self.messages._project_message_ids(project_id)
            ]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self.tasks._get(task_id)
            return [
                self.messages._messages[m].clone()
                for m in self.messages._task_message_ids(task_id)
            ]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self.messages._get(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            self.messages._remove(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self.users._get(user_id)
            task_ids = self.tasks._assignee_task_ids(user_id)
            if not task_ids:
                return 0.0
            completed = sum(
                1
                for t in task_ids
                if self.tasks._tasks[t].status == TaskStatus.COMPLETED
            )
            return completed / len(task_ids)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self.users._get(user_id)
            durations = self._completion_durations(
                self.tasks._assignee_task_ids(user_id)
            )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def _completion_durations(self, task_ids) -> List[float]:
        durations: List[float] = []
        for task_id in task_ids:
            task = self.tasks._tasks[task_id]
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            self.users._get(rater_id)
            self.users._get(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self.tasks._get(task_id)
            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._add_rating(rating)
            return rating.clone()

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self.users._get(user_id)
            ratings = self.performance._ratings_for(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self.users._get(user_id)
            task_ids = self.tasks._assignee_task_ids(user_id)
            total = len(task_ids)
            completed = in_progress = not_started = 0
            for task_id in task_ids:
                status = self.tasks._tasks[task_id].status
                if status == TaskStatus.COMPLETED:
                    completed += 1
                elif status == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                else:
                    not_started += 1
            durations = self._completion_durations(task_ids)
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self.performance._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self.projects._get(project_id)
            task_ids = self.tasks._project_task_ids(project_id)
            total = len(task_ids)
            status_counts = {status.value: 0 for status in TaskStatus}
            completed = 0
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            now = self._now()
            for task_id in task_ids:
                task = self.tasks._tasks[task_id]
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.status != TaskStatus.COMPLETED
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self.projects._get(project_id)
                tasks = [
                    self.tasks._tasks[t]
                    for t in self.tasks._project_task_ids(project_id)
                ]
            else:
                tasks = list(self.tasks._tasks.values())

            by_user: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user.keys()):
                rows.append(self._performance_row(user_id, by_user[user_id]))
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def _performance_row(self, user_id: int, tasks: List[Task]) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        average_completion_time = (
            sum(durations) / len(durations) if durations else None
        )
        ratings = self.performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        user = self.users._users.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else "",
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": average_completion_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            user = self.users._get(user_id)
            task_ids = self.tasks._assignee_task_ids(user_id)
            tasks = [self.tasks._tasks[t] for t in task_ids]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            durations = self._completion_durations(task_ids)
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self.performance._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "assignee_id": t.assignee_id,
                    "deadline": t.deadline.isoformat() if t.deadline else None,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._report_to_csv(report)
            if report_format == ReportFormat.PDF:
                return self._report_to_pdf(report)
            raise ValidationError("unsupported report format")

    # -- export helpers ----------------------------------------------------
    @staticmethod
    def _stringify(value) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list, tuple)):
            return repr(value)
        return str(value)

    def _report_to_csv(self, report: dict) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list):
            headers: List[str] = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row.keys():
                        if key not in headers:
                            headers.append(key)
            if not headers:
                headers = ["user_id"]
            writer.writerow(headers)
            for row in rows:
                if isinstance(row, dict):
                    writer.writerow(
                        [self._stringify(row.get(h, "")) for h in headers]
                    )
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._stringify(value)])
        return buffer.getvalue()

    def _report_to_pdf(self, report: dict) -> bytes:
        lines = ["Report: " + self._stringify(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, self._stringify(value)))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF writer
# ---------------------------------------------------------------------------
def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal, structurally valid single-page PDF document."""

    def escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        )

    content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(lines):
        if index > 0:
            content_parts.append("T*")
        content_parts.append("({0}) Tj".format(escape(line)))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, obj in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(number).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

    xref_position = len(pdf)
    size = len(objects) + 1
    pdf += b"xref\n0 " + str(size).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
    pdf += b"startxref\n" + str(xref_position).encode("ascii") + b"\n%%EOF"
    return bytes(pdf)
